import React from 'react';
import { X } from 'lucide-react';
import OptimizationActionChip from './OptimizationActionChip';
import ConfidenceScore from './ConfidenceScore';
import { formatCurrency } from '../../utils/format';
import { workflowStatusLabel } from '../../utils/actionUtils';
import { resourceGroupLabelForAction } from '../../utils/optimizationGrouping';
import {
  parseActionAnalysis,
  tierLabel,
  tierTone,
  optimizationDataQualityLabel,
  optimizationMetricStatusLabel,
} from '../../utils/actionAnalysisUtils';

function DimensionRow({ label, value }) {
  if (value == null) return null;
  const pct = Math.round(Number(value));
  return (
    <div className="action-analysis-dimension">
      <div className="action-analysis-dimension__header">
        <span>{label}</span>
        <span>{pct}</span>
      </div>
      <div className="action-analysis-dimension__track">
        <div
          className="action-analysis-dimension__fill"
          style={{ width: `${Math.min(100, Math.max(0, pct))}%` }}
        />
      </div>
    </div>
  );
}

function MetricsTable({ title, metrics }) {
  if (!metrics?.length) return null;
  return (
    <div className="drawer-investigation">
      <h4 className="drawer-investigation__title">{title}</h4>
      <table className="finding-evidence__table finding-evidence__metrics-table">
        <thead>
          <tr>
            <th scope="col">Metric</th>
            <th scope="col">Value</th>
            <th scope="col">Status</th>
          </tr>
        </thead>
        <tbody>
          {metrics.map((metric) => (
            <tr key={metric.id || metric.label}>
              <td>{metric.label}</td>
              <td>{metric.formatted ?? metric.value ?? '—'}</td>
              <td>{optimizationMetricStatusLabel(metric.status) || '—'}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default function ActionDetailDrawer({
  action,
  currency = 'USD',
  onClose,
  onApproveClick,
  isAdmin = false,
}) {
  if (!action) return null;

  const analysis = parseActionAnalysis(action);
  const { cost, utilization, metrics, rules, tier, overallScore, dimensions, workload } = analysis;

  return (
    <div className="action-detail-drawer-overlay" role="presentation" onClick={onClose}>
      <div
        className="action-detail-drawer"
        role="dialog"
        aria-labelledby="action-detail-title"
        onClick={(e) => e.stopPropagation()}
      >
        <header className="action-detail-drawer__header">
          <div>
            <h2 id="action-detail-title" className="action-detail-drawer__title">
              {action.resource_name}
            </h2>
            <p className="action-detail-drawer__subtitle">
              {action.resource_type} • {action.resource_group || resourceGroupLabelForAction(action)}
            </p>
          </div>
          <button
            type="button"
            className="btn-icon"
            onClick={onClose}
            aria-label="Close"
          >
            <X size={20} />
          </button>
        </header>

        <div className="action-detail-drawer__body">
          <section className="drawer-section">
            <h3 className="drawer-section__title">Action summary</h3>
            <div className="drawer-summary-grid">
              <div className="drawer-summary-item">
                <span className="drawer-summary-label">Type</span>
                <div className="drawer-summary-value">
                  <OptimizationActionChip actionType={action.action_type} />
                </div>
              </div>
              <div className="drawer-summary-item">
                <span className="drawer-summary-label">Confidence</span>
                <div className="drawer-summary-value">
                  <ConfidenceScore confidence={action.confidence} compact />
                </div>
              </div>
              <div className="drawer-summary-item">
                <span className="drawer-summary-label">Status</span>
                <div className="drawer-summary-value">
                  <span className="workflow-pill">
                    {workflowStatusLabel(action.workflow_status)}
                  </span>
                </div>
              </div>
              {tier && (
                <div className="drawer-summary-item">
                  <span className="drawer-summary-label">Tier</span>
                  <div className="drawer-summary-value">
                    <span className={`tier-pill tier-pill--${tierTone(tier)}`}>
                      {tierLabel(tier)}
                    </span>
                  </div>
                </div>
              )}
              {overallScore != null && (
                <div className="drawer-summary-item">
                  <span className="drawer-summary-label">Overall score</span>
                  <div className="drawer-summary-value">{Math.round(overallScore)}</div>
                </div>
              )}
              {action.estimated_monthly_savings > 0 && (
                <div className="drawer-summary-item">
                  <span className="drawer-summary-label">Est. savings/mo</span>
                  <div className="drawer-summary-value text-highlight">
                    {formatCurrency(action.estimated_monthly_savings, { currency })}
                  </div>
                </div>
              )}
            </div>
          </section>

          {action.action_reason && (
            <section className="drawer-section">
              <h3 className="drawer-section__title">Recommendation</h3>
              <p className="drawer-section-text">{action.action_reason}</p>
            </section>
          )}

          <section className="drawer-section">
            <h3 className="drawer-section__title">Analysis</h3>

            <div className="drawer-investigation">
              <h4 className="drawer-investigation__title">Cost</h4>
              {cost.current_monthly_cost != null && (
                <div className="drawer-investigation-field">
                  <span className="drawer-investigation-label">Current monthly cost:</span>
                  <span>{formatCurrency(cost.current_monthly_cost, { currency })}</span>
                </div>
              )}
              {cost.estimated_monthly_savings > 0 && (
                <div className="drawer-investigation-field">
                  <span className="drawer-investigation-label">Est. savings:</span>
                  <span className="text-highlight">
                    {formatCurrency(cost.estimated_monthly_savings, { currency })}
                  </span>
                </div>
              )}
              {cost.savings_confidence != null && (
                <div className="drawer-investigation-field">
                  <span className="drawer-investigation-label">Savings confidence:</span>
                  <span>{Math.round(cost.savings_confidence)}%</span>
                </div>
              )}
              {cost.payback_months != null && (
                <div className="drawer-investigation-field">
                  <span className="drawer-investigation-label">Payback:</span>
                  <span>{cost.payback_months} mo</span>
                </div>
              )}
              {cost.implementation_effort && (
                <div className="drawer-investigation-field">
                  <span className="drawer-investigation-label">Effort:</span>
                  <span>{cost.implementation_effort}</span>
                </div>
              )}
            </div>

            {Object.keys(dimensions).length > 0 && (
              <div className="drawer-investigation">
                <h4 className="drawer-investigation__title">Score dimensions</h4>
                <div className="action-analysis-dimensions">
                  <DimensionRow label="Cost" value={dimensions.cost} />
                  <DimensionRow label="Safety" value={dimensions.safety} />
                  <DimensionRow label="Effort" value={dimensions.effort} />
                  <DimensionRow label="Workload" value={dimensions.workload} />
                  <DimensionRow label="Business" value={dimensions.business} />
                </div>
              </div>
            )}

            {workload.workload_type && (
              <div className="drawer-investigation">
                <h4 className="drawer-investigation__title">Workload</h4>
                <div className="drawer-investigation-field">
                  <span className="drawer-investigation-label">Type:</span>
                  <span>{workload.workload_type}</span>
                </div>
                {workload.utilization_trend && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Trend:</span>
                    <span>{workload.utilization_trend}</span>
                  </div>
                )}
                {utilization.workload_stability_score != null && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Stability score:</span>
                    <span>{Math.round(utilization.workload_stability_score)}</span>
                  </div>
                )}
              </div>
            )}

            <MetricsTable title="Cost metrics" metrics={metrics?.cost} />
            <MetricsTable title="Utilization metrics" metrics={metrics?.performance} />

            {analysis.dataQuality && (
              <p className="text-muted text-sm">
                Data: {optimizationDataQualityLabel(analysis.dataQuality)}
              </p>
            )}

            {(utilization.performance_risk_score != null || utilization.dependency_blast_radius != null) && (
              <div className="drawer-investigation">
                <h4 className="drawer-investigation__title">Risk</h4>
                {utilization.performance_risk_score != null && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Performance risk:</span>
                    <span>{Math.round(utilization.performance_risk_score)}</span>
                  </div>
                )}
                {utilization.dependency_blast_radius != null && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Dependency blast radius:</span>
                    <span>{utilization.dependency_blast_radius}</span>
                  </div>
                )}
                {action.performance_risk && (
                  <div className="drawer-investigation-field">
                    <span className="drawer-investigation-label">Risk level:</span>
                    <span>{action.performance_risk}</span>
                  </div>
                )}
              </div>
            )}

            {rules.length > 0 && (
              <div className="drawer-investigation">
                <h4 className="drawer-investigation__title">Signals applied</h4>
                <ul className="drawer-rules-list">
                  {rules.map((rule) => (
                    <li key={rule} className="drawer-rules-item">{rule}</li>
                  ))}
                </ul>
              </div>
            )}

            {!cost.current_monthly_cost
              && !metrics?.cost?.length
              && !metrics?.performance?.length
              && rules.length === 0 && (
              <p className="text-muted text-sm">Run engine scoring to refresh analysis for this action.</p>
            )}
          </section>
        </div>

        <footer className="action-detail-drawer__footer">
          <button
            type="button"
            className="btn btn--ghost"
            onClick={onClose}
          >
            Close
          </button>
          {isAdmin && (
            <button
              type="button"
              className="btn btn--primary"
              onClick={onApproveClick}
            >
              Approve/Update
            </button>
          )}
        </footer>
      </div>
    </div>
  );
}
